mapper.insert:
		/*
             SQL ID : SmnrTrgtrDAO.smnrTrgtrBulkRegist
             설  명 : 세미나대상자일괄등록
         */
         INSERT ALL

			INTO TB_LMS_SMNR_TRGTR (
	         	  SMNR_TRGTR_ID
				, SMNR_ID
				, USER_ID
				, ONLN_MEETNGRM_ID
				, TRGTR_CNTN_URL
				, PREREGYN
				, RGTR_ID
				, REG_DTTM
	         ) VALUES (
	         	  #{item.smnrTrgtrId}
				, #{item.smnrId}
				, #{item.userId}
				, #{item.onlnMeetngrmId}
				, #{item.trgtrCntnUrl}
				, #{item.preregyn}
				, #{item.rgtrId}
				, FN_DTTM()
	         )

		SELECT * FROM DUAL

mapper.delete:
		/*
             SQL ID : SmnrTrgtrDAO.smnrTrgtrBulkDelete
             설  명 : 세미나대상자일괄삭제
         */
        DELETE FROM TB_LMS_SMNR_TRGTR
         WHERE SMNR_ID = #{smnrId}
